<div class="d-flex flex-wrap justify-content-between align-items-center gap-3 mb-4"><div><h1 class="h3 mb-1">Crew Calendar</h1><p class="text-muted mb-0">Two-week crew workload and unassigned-job view.</p></div><form class="d-flex gap-2"><input class="form-control" type="date" name="start" value="<?=e($start)?>"><select class="form-select" name="days"><option value="7" <?=selected($days,7)?>>7 days</option><option value="14" <?=selected($days,14)?>>14 days</option><option value="31" <?=selected($days,31)?>>31 days</option></select><button class="btn btn-primary">Load</button></form></div>
<div class="table-responsive"><table class="table table-bordered align-middle"><thead><tr><th style="min-width:160px">Crew</th><?php foreach($dates as $date):?><th style="min-width:150px"><?=e(date('D M j',strtotime($date)))?></th><?php endforeach?></tr></thead><tbody><?php foreach($crews as $crew):?><tr><th><div><?=e($crew['name'])?></div><small class="text-muted"><?=e($crew['leader_name']?:'No leader')?></small></th><?php foreach($dates as $date):?><td><?php $dayJobs=array_filter($jobs,fn($j)=>(int)$j['crew_id']===(int)$crew['id']&&date('Y-m-d',strtotime($j['scheduled_start']))===$date);?><?php foreach($dayJobs as $job):?><a href="/portal/jobs/<?=$job['id']?>" class="d-block border rounded p-2 mb-2 text-decoration-none"><strong><?=e(date('g:i A',strtotime($job['scheduled_start'])))?></strong><br><span><?=e($job['customer_name'])?></span><br><small><?=e($job['service_summary'])?></small></a><?php endforeach?><?php if(!$dayJobs):?><span class="text-muted small">Open</span><?php endif?></td><?php endforeach?></tr><?php endforeach?></tbody></table></div>
